89	type Policy = {
90	  items: Item[];
91	  remainingCap: number;
92	};
93	
94	const damagePayout = (damage: Damage, item: Item): number => {
95	  const reimbursed = damage.amount;
96	  return Math.max(0, reimbursed - DEDUCTIBLE);
97	};
98	
99	const claim = (incident: Incident, policy: Policy): ClaimResult => {
100	  let totalPayout = 0;
101	  for (const damage of incident.damages) {
102	    const item = policy.items.find((i) => i.type === damage.itemType);
103	    if (!item) continue;
104	    totalPayout += damagePayout(damage, item);
105	  }
106	  const actualPayout = Math.min(totalPayout, policy.remainingCap);
107	  policy.remainingCap -= actualPayout;
108	  return { payout: actualPayout, remainingCap: policy.remainingCap };
109	};
