111	export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
112	  let quoteCount = 0;
113	  const policies: Record<number, Policy> = {};
114	  const results: StepResult[] = scenario.steps.map((step, index) => {
115	    if (step.op === "quote") {
116	      const isFollowUp = quoteCount > 0;
117	      quoteCount += 1;
118	      const sum = insuranceSum(step.items);
119	      policies[index] = { items: step.items, remainingCap: sum * 2 };
120	      return quote(step.items, scenario.customer, isFollowUp);
121	    } else {
122	      return claim(step.incident, policies[step.policy]);
123	    }
124	  });
125	  return { results };
126	};
