const damagePayout = (damage: Damage): number =>
  Math.max(0, damage.amount - DEDUCTIBLE);

const isInsured = (policy: Policy, damage: Damage): boolean =>
  policy.items.some((item) => item.type === damage.itemType);

const claim = (incident: Incident, policy: Policy): ClaimResult => {
  const grossPayout = incident.damages
    .filter((damage) => isInsured(policy, damage))
    .reduce((sum, damage) => sum + damagePayout(damage), 0);
  const payout = Math.min(grossPayout, policy.remainingCap);
  policy.remainingCap -= payout;
  return { payout, remainingCap: policy.remainingCap };
